def detect_fts(conn, table):

    cursor = conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='{}'".format(table))
    result = cursor.fetchone()
    if result:
        fts_table = "{}_fts".format(table)
        cursor = conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='{}'".format(fts_table))
        fts_result = cursor.fetchone()
        if fts_result:
            return fts_table
    return None


